@import "tailwindcss";

/*
 * TWYNE — The Editorial Room
 * ─────────────────────────────────────────────────────────────
 * Design language: a 1955 magazine bullpen filtered through
 * Wes Anderson's "The French Dispatch."  Newsprint paper,
 * editorial vermilion, periwinkle and sage departmental
 * accents, hot-press serif headlines, manuscript-grade body.
 * ─────────────────────────────────────────────────────────────
 */

@theme {
  /* ── Paper & Ink ─────────────────────────────────────── */
  --color-paper: #f4ecd8; /* aged newsprint cream */
  --color-paper-2: #ebe1c9; /* deeper paper, sidebars */
  --color-paper-3: #ddd0b1; /* paper rule */
  --color-paper-soft: #faf3df; /* highlight paper */
  --color-ink: #1f1b16; /* near-black brown */
  --color-ink-light: #4a3f33; /* secondary ink */
  --color-ink-muted: #8a7e6c; /* tertiary, set in old gravure */
  --color-editor-bg: #fbf6e7; /* manuscript page */
  --color-editor-line: #efe6cb; /* manuscript ledger line */

  /* ── Departmental Accents (color-coded sections) ─────── */
  --color-vermilion: #c1272d; /* Penguin Classics red, masthead */
  --color-vermilion-2: #9c1a1f; /* deeper vermilion */
  --color-periwinkle: #5c6bc0; /* periwinkle, departmental */
  --color-sage: #8a9a5b; /* cabinet sage */
  --color-mustard: #d4a017; /* color rule, badges */
  --color-blush: #e8a598; /* salmon, soft accents */
  --color-cobalt: #2c4a7c; /* deep ocean, callouts */

  /* legacy "brand" mapped to vermilion for compat */
  --color-brand: #c1272d;
  --color-brand-light: #d65157;
  --color-brand-dark: #9c1a1f;

  /* legacy "surface" mapped to paper for compat */
  --color-surface: #f4ecd8;
  --color-surface-2: #ebe1c9;
  --color-surface-3: #ddd0b1;

  /* ── Status colors (kept, but recalibrated for paper) ── */
  --color-accent-green: #5b7a3a;
  --color-accent-amber: #b8860b;
  --color-accent-red: #b3261e;
  --color-accent-blue: #2c4a7c;

  /* ── Cast colors (the persona portraits) ─────────────── */
  --color-persona-devil: #c1272d; /* vermilion */
  --color-persona-angel: #8a9a5b; /* sage */
  --color-persona-scholar: #5c6bc0; /* periwinkle */
  --color-persona-editor: #d4a017; /* mustard */
  --color-persona-reader: #2c4a7c; /* cobalt */

  /* ── Type stack ──────────────────────────────────────── */
  --font-display: "Fraunces", "Playfair Display", Georgia, serif;
  --font-serif: "Lora", "Crimson Pro", Georgia, "Times New Roman", serif;
  --font-sans: "DM Sans", "Inter", system-ui, sans-serif;
  --font-mono: "JetBrains Mono", "Fira Code", monospace;
  --font-typewriter: "Special Elite", "Courier New", monospace;
}

/* ── Semantic z-scale ────────────────────────────────────── */
:root {
  --z-dropdown: 30;
  --z-sticky: 20;
  --z-overlay: 40;
  --z-modal: 50;
  --z-toast: 60;
}

/* ── Page foundation ─────────────────────────────────────── */
* {
  scrollbar-width: thin;
  scrollbar-color: var(--color-paper-3) transparent;
}

body {
  font-family: var(--font-sans);
  color: var(--color-ink);
  background-color: var(--color-paper);
  /* Subtle paper grain — barely-there noise to give the surface tooth */
  background-image:
    radial-gradient(
      circle at 25% 35%,
      rgba(31, 27, 22, 0.025) 0,
      transparent 1px
    ),
    radial-gradient(
      circle at 75% 65%,
      rgba(31, 27, 22, 0.02) 0,
      transparent 1px
    ),
    radial-gradient(
      circle at 45% 85%,
      rgba(31, 27, 22, 0.015) 0,
      transparent 1px
    );
  background-size:
    7px 7px,
    11px 11px,
    13px 13px;
  font-feature-settings:
    "kern",
    "liga",
    "onum" 1;
}

/* ── Editorial chrome utilities ──────────────────────────── */
.masthead-rule {
  position: relative;
}
.masthead-rule::before,
.masthead-rule::after {
  content: "";
  display: block;
  height: 1px;
  background: var(--color-ink);
}
.masthead-rule::before {
  margin-bottom: 4px;
}
.masthead-rule::after {
  margin-top: 4px;
  height: 3px;
}

.dept-label {
  font-family: var(--font-typewriter);
  font-size: 0.625rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
}

.ornament-divider {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  color: var(--color-ink-muted);
  font-family: var(--font-display);
  font-size: 0.875rem;
}
.ornament-divider::before,
.ornament-divider::after {
  content: "";
  flex: 1;
  height: 1px;
  background: var(--color-paper-3);
}

/* Stamped, rubber-stamp aesthetic for completed states */
.stamp {
  display: inline-block;
  padding: 0.3rem 0.7rem;
  border: 2px solid var(--color-vermilion);
  color: var(--color-vermilion);
  font-family: var(--font-typewriter);
  font-size: 0.6875rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  transform: rotate(-3deg);
  background: rgba(193, 39, 45, 0.04);
  border-radius: 2px;
}

/* Index card surface */
.index-card {
  background: var(--color-paper-soft);
  background-image: repeating-linear-gradient(
    to bottom,
    transparent 0,
    transparent 27px,
    rgba(92, 107, 192, 0.18) 27px,
    rgba(92, 107, 192, 0.18) 28px
  );
  border: 1px solid var(--color-paper-3);
  box-shadow:
    0 1px 0 rgba(31, 27, 22, 0.04),
    0 6px 14px -10px rgba(31, 27, 22, 0.18);
  position: relative;
}
.index-card::before {
  /* the red top margin of an index card */
  content: "";
  position: absolute;
  top: 24px;
  left: 0;
  right: 0;
  height: 1px;
  background: var(--color-vermilion);
  opacity: 0.55;
}

/* Dossier folder edge */
.folio {
  background: var(--color-paper-soft);
  border: 1px solid var(--color-paper-3);
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.6) inset,
    0 14px 32px -22px rgba(31, 27, 22, 0.4),
    0 2px 0 rgba(31, 27, 22, 0.05);
}

/* ── Tiptap manuscript page ──────────────────────────────── */
.twyne-editor .ProseMirror {
  outline: none;
  min-height: 60vh;
  font-family: var(--font-serif);
  font-size: 1.125rem;
  line-height: 1.8;
  color: var(--color-ink);
  font-feature-settings:
    "kern",
    "liga",
    "onum" 1;
}

.twyne-editor .ProseMirror p {
  margin-bottom: 0.85em;
  text-align: justify;
  hyphens: auto;
  -webkit-hyphens: auto;
}

/* Drop cap on the very first paragraph — the magazine touch */
.twyne-editor .ProseMirror > p:first-of-type::first-letter {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 4.2em;
  float: left;
  line-height: 0.85;
  margin: 0.08em 0.12em -0.05em 0;
  color: var(--color-vermilion);
}

.twyne-editor .ProseMirror h1 {
  font-family: var(--font-display);
  font-size: 2.5rem;
  font-weight: 700;
  letter-spacing: -0.01em;
  margin-top: 1.2em;
  margin-bottom: 0.45em;
  line-height: 1.1;
  color: var(--color-ink);
  text-align: center;
}

.twyne-editor .ProseMirror h1::after {
  content: "✦";
  display: block;
  text-align: center;
  color: var(--color-vermilion);
  font-size: 1rem;
  margin-top: 0.3em;
  letter-spacing: 0.5em;
}

.twyne-editor .ProseMirror h2 {
  font-family: var(--font-display);
  font-size: 1.5rem;
  font-weight: 600;
  margin-top: 1.5em;
  margin-bottom: 0.4em;
  line-height: 1.25;
  color: var(--color-ink);
}

.twyne-editor .ProseMirror h3 {
  font-family: var(--font-sans);
  font-size: 0.75rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  font-weight: 700;
  margin-top: 1.6em;
  margin-bottom: 0.4em;
  color: var(--color-vermilion);
}

.twyne-editor .ProseMirror blockquote {
  border-left: 3px solid var(--color-vermilion);
  padding: 0.4em 1.25em;
  margin: 1.2em 0 1.2em 0;
  color: var(--color-ink-light);
  font-family: var(--font-display);
  font-style: italic;
  font-size: 1.25em;
  line-height: 1.55;
}

/* Checklists — task list with editorial checkboxes */
.twyne-editor .ProseMirror ul.twyne-task-list,
.twyne-editor .ProseMirror ul[data-type="taskList"] {
  list-style: none;
  padding-left: 0.2em;
}
.twyne-editor .ProseMirror ul[data-type="taskList"] li {
  display: flex;
  align-items: flex-start;
  gap: 0.55em;
  margin: 0.25em 0;
}
.twyne-editor .ProseMirror ul[data-type="taskList"] li > label {
  margin-top: 0.28em;
  user-select: none;
}
.twyne-editor .ProseMirror ul[data-type="taskList"] li > label input[type="checkbox"] {
  appearance: none;
  width: 1.05em;
  height: 1.05em;
  border: 1.5px solid var(--color-paper-3);
  border-radius: 2px;
  background: var(--color-paper);
  cursor: pointer;
  position: relative;
  transition: background 0.12s ease, border-color 0.12s ease;
}
.twyne-editor .ProseMirror ul[data-type="taskList"] li > label input[type="checkbox"]:checked {
  background: var(--color-vermilion);
  border-color: var(--color-vermilion);
}
.twyne-editor .ProseMirror ul[data-type="taskList"] li > label input[type="checkbox"]:checked::after {
  content: "✓";
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.8em;
  color: var(--color-paper);
}
.twyne-editor .ProseMirror ul[data-type="taskList"] li > div {
  flex: 1;
}
.twyne-editor .ProseMirror ul[data-type="taskList"] li[data-checked="true"] > div {
  color: var(--color-ink-muted);
  text-decoration: line-through;
}

.twyne-editor .ProseMirror code {
  font-family: var(--font-mono);
  background: var(--color-paper-2);
  padding: 0.15em 0.4em;
  border-radius: 2px;
  font-size: 0.88em;
}

.twyne-editor .ProseMirror pre {
  background: var(--color-ink);
  color: var(--color-paper);
  padding: 1em 1.25em;
  border-radius: 2px;
  overflow-x: auto;
  border-left: 4px solid var(--color-mustard);
}

.twyne-editor .ProseMirror pre code {
  background: none;
  padding: 0;
  font-size: 0.875rem;
}

.twyne-editor .ProseMirror img {
  max-width: 100%;
  border: 6px solid white;
  box-shadow:
    0 1px 0 var(--color-paper-3),
    0 18px 30px -18px rgba(31, 27, 22, 0.45);
  margin: 1.4em auto;
  display: block;
}

.twyne-editor .ProseMirror img.ProseMirror-selectednode {
  outline: 2px solid var(--color-vermilion);
}

.twyne-editor .ProseMirror table {
  border-collapse: collapse;
  width: 100%;
  margin: 1em 0;
  font-family: var(--font-sans);
  font-size: 0.95rem;
}

.twyne-editor .ProseMirror table td,
.twyne-editor .ProseMirror table th {
  border: 1px solid var(--color-paper-3);
  padding: 0.55em 0.8em;
  text-align: left;
}

.twyne-editor .ProseMirror table th {
  background: var(--color-paper-2);
  font-weight: 700;
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.twyne-editor .ProseMirror .columnResizorHandle {
  background-color: var(--color-vermilion);
}

.twyne-editor .ProseMirror mark {
  background: linear-gradient(transparent 60%, rgba(212, 160, 23, 0.45) 60%);
  padding: 0;
  border-radius: 0;
}

.twyne-editor .ProseMirror hr {
  border: none;
  text-align: center;
  margin: 2em 0;
}
.twyne-editor .ProseMirror hr::before {
  content: "❦";
  color: var(--color-vermilion);
  font-size: 1.1rem;
  letter-spacing: 0.5em;
}

.twyne-editor .ProseMirror .is-editor-empty:first-child::before {
  content: attr(data-placeholder);
  float: left;
  color: var(--color-ink-muted);
  pointer-events: none;
  height: 0;
  font-style: italic;
  font-family: var(--font-display);
}

/* Citation: a hot-pencil underline */
.twyne-editor .ProseMirror .citation-mark {
  background-color: rgba(92, 107, 192, 0.1);
  border-bottom: 2px dotted var(--color-periwinkle);
  cursor: pointer;
}

/* Comment: marginalia highlight */
.twyne-editor .ProseMirror .comment-mark {
  background-color: rgba(212, 160, 23, 0.18);
  border-bottom: 2px solid var(--color-mustard);
  cursor: pointer;
}

/* Persona feedback line decoration */
.persona-feedback-card {
  border-left-width: 3px;
}

/* Drag-over overlay */
.drag-overlay {
  position: fixed;
  inset: 0;
  background: rgba(193, 39, 45, 0.07);
  border: 2px dashed var(--color-vermilion);
  z-index: var(--z-overlay);
  display: flex;
  align-items: center;
  justify-content: center;
  pointer-events: none;
}

.drag-overlay span {
  background: var(--color-vermilion);
  color: var(--color-paper);
  padding: 0.75em 1.5em;
  border-radius: 2px;
  font-family: var(--font-typewriter);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  font-size: 0.75rem;
}

/* Scrollbar for panels */
.panel-scroll {
  overflow-y: auto;
  max-height: calc(100vh - 3rem);
}

.sidebar-transition {
  transition:
    width 0.2s ease,
    opacity 0.2s ease,
    transform 0.2s ease;
}

.focus-ring:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: 2px;
}

/* Rubric score animation — fills from 0 to the inline width */
@keyframes rubric-fill {
  from {
    width: 0;
  }
}

.rubric-bar {
  animation: rubric-fill 0.6s ease-out forwards;
}

/* A subtle hand-set wobble for the masthead — French Dispatch nod */
@keyframes presswobble {
  0%,
  100% {
    transform: translate(0, 0) rotate(0deg);
  }
  25% {
    transform: translate(0.2px, -0.1px) rotate(-0.05deg);
  }
  75% {
    transform: translate(-0.15px, 0.1px) rotate(0.05deg);
  }
}
.press {
  animation: presswobble 4s ease-in-out infinite;
  display: inline-block;
}

/* Editorial button — a small set, hot-press feel */
.btn-press {
  font-family: var(--font-typewriter);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  font-size: 0.7rem;
  padding: 0.55rem 1rem;
  background: var(--color-ink);
  color: var(--color-paper);
  border: 1px solid var(--color-ink);
  border-radius: 2px;
  transition:
    transform 0.1s ease,
    background 0.15s ease;
  cursor: pointer;
}
.btn-press:hover {
  background: var(--color-vermilion-2);
  border-color: var(--color-vermilion-2);
}
.btn-press:active {
  transform: translateY(1px);
}
.btn-press:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.btn-paper {
  font-family: var(--font-sans);
  font-size: 0.75rem;
  font-weight: 600;
  padding: 0.45rem 0.9rem;
  background: var(--color-paper-soft);
  color: var(--color-ink);
  border: 1px solid var(--color-paper-3);
  border-radius: 2px;
  transition: background 0.15s ease;
  cursor: pointer;
}
.btn-paper:hover {
  background: var(--color-paper-2);
}

.btn-press:focus-visible,
.btn-paper:focus-visible,
.landing-button:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: 2px;
}

/* Small icon-only control — consistent hit target + accessible focus */
.icon-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 1.75rem;
  min-height: 1.75rem;
  border-radius: 2px;
  color: var(--color-ink-muted);
  transition:
    color 0.15s ease,
    background 0.15s ease;
  cursor: pointer;
}
.icon-btn:hover {
  color: var(--color-ink);
  background: var(--color-paper-2);
}
.icon-btn:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: 1px;
}

/* Editor toolbar button — supports a pressed/active state */
.tool-btn {
  padding: 0.25rem 0.5rem;
  font-size: 0.875rem;
  color: var(--color-ink-light);
  border-radius: 2px;
  transition:
    color 0.15s ease,
    background 0.15s ease;
  cursor: pointer;
}
.tool-btn:hover {
  color: var(--color-vermilion);
  background: var(--color-paper-soft);
}
.tool-btn[aria-pressed="true"] {
  color: var(--color-vermilion);
  background: var(--color-paper-2);
  box-shadow: inset 0 -2px 0 var(--color-vermilion);
}
.tool-btn:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: -2px;
}

/* Editorial form controls — shared input vocabulary */
.field-label {
  display: block;
  font-family: var(--font-typewriter);
  font-size: 0.625rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-light);
  margin-bottom: 0.35rem;
}
.field-input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  font-family: var(--font-serif);
  font-size: 0.875rem;
  color: var(--color-ink);
  background: var(--color-paper-soft);
  border: 1px solid var(--color-paper-3);
  border-radius: 2px;
}
.field-input::placeholder {
  color: var(--color-ink-muted);
  font-style: italic;
}
.field-input:focus {
  outline: none;
  border-color: var(--color-vermilion);
}
.field-input:focus-visible {
  outline: 1px solid var(--color-vermilion);
  outline-offset: 0;
}

/* Inline error note — letterpress slip, not a toast */
.error-slip {
  padding: 0.6rem 0.8rem;
  border: 1px solid var(--color-vermilion);
  background: rgba(193, 39, 45, 0.05);
  border-radius: 2px;
  color: var(--color-vermilion-2);
  font-family: var(--font-serif);
  font-size: 0.8125rem;
  line-height: 1.45;
}

/* Landing page surfaces */
.landing-page {
  position: relative;
  overflow: clip;
  background:
    radial-gradient(
      circle at top left,
      rgba(193, 39, 45, 0.08),
      transparent 26%
    ),
    radial-gradient(
      circle at 82% 18%,
      rgba(92, 107, 192, 0.08),
      transparent 18%
    ),
    linear-gradient(180deg, #f7f1e2 0%, #f4ecd8 34%, #f2e7cf 100%);
}

.landing-page::before {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  background-image:
    radial-gradient(
      circle at 15% 20%,
      rgba(31, 27, 22, 0.025) 0,
      transparent 1px
    ),
    radial-gradient(
      circle at 70% 40%,
      rgba(31, 27, 22, 0.02) 0,
      transparent 1px
    ),
    radial-gradient(
      circle at 85% 78%,
      rgba(31, 27, 22, 0.015) 0,
      transparent 1px
    );
  background-size:
    9px 9px,
    11px 11px,
    13px 13px;
  opacity: 0.45;
}

.landing-shell {
  position: relative;
  z-index: 1;
  width: min(1440px, calc(100% - 1.5rem));
  margin: 0 auto;
}

.landing-frame {
  background: rgba(250, 243, 223, 0.7);
  border: 1px solid rgba(122, 30, 34, 0.08);
  border-radius: 28px;
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.7) inset,
    0 40px 80px -52px rgba(31, 27, 22, 0.28);
  backdrop-filter: blur(10px);
}

.landing-kicker {
  font-family: var(--font-typewriter);
  letter-spacing: 0.28em;
  text-transform: uppercase;
  font-size: 0.7rem;
  color: var(--color-ink-muted);
}

.landing-title {
  font-family: var(--font-display);
  color: var(--color-ink);
  letter-spacing: -0.03em;
}

.landing-deck {
  font-family: var(--font-serif);
  color: var(--color-ink-light);
  line-height: 1.7;
}

.landing-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.55rem;
  min-height: 2.8rem;
  padding: 0.7rem 1.4rem;
  border-radius: 999px;
  border: 1px solid transparent;
  font-family: var(--font-typewriter);
  font-size: 0.75rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  transition:
    transform 0.15s ease,
    background 0.15s ease,
    border-color 0.15s ease;
}

.landing-button:hover {
  transform: translateY(-1px);
}

.landing-button.primary {
  background: var(--color-vermilion);
  color: var(--color-paper);
  border-color: var(--color-vermilion);
}

.landing-button.primary:hover {
  background: var(--color-vermilion-2);
  border-color: var(--color-vermilion-2);
}

.landing-button.secondary {
  background: transparent;
  color: var(--color-ink);
  border-color: rgba(31, 27, 22, 0.28);
}

.landing-chip {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.4rem 0.85rem;
  border-radius: 999px;
  border: 1px solid rgba(31, 27, 22, 0.1);
  background: rgba(250, 243, 223, 0.55);
  font-family: var(--font-typewriter);
  font-size: 0.64rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
}

.landing-section-title {
  font-family: var(--font-display);
  color: var(--color-ink);
  letter-spacing: -0.02em;
}

.landing-feature-card {
  background: rgba(250, 243, 223, 0.78);
  border: 1px solid rgba(31, 27, 22, 0.06);
  border-radius: 22px;
  box-shadow: 0 18px 38px -28px rgba(31, 27, 22, 0.22);
  transition:
    transform 0.2s ease,
    box-shadow 0.2s ease;
}
.landing-feature-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 26px 48px -30px rgba(31, 27, 22, 0.3);
}

.landing-preview {
  background:
    linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.82),
      rgba(245, 236, 216, 0.95)
    ),
    repeating-linear-gradient(
      to bottom,
      transparent 0,
      transparent 29px,
      rgba(92, 107, 192, 0.12) 29px,
      rgba(92, 107, 192, 0.12) 30px
    );
  border: 1px solid rgba(31, 27, 22, 0.08);
  border-radius: 20px;
  box-shadow:
    0 2px 0 rgba(255, 255, 255, 0.6) inset,
    0 44px 80px -48px rgba(31, 27, 22, 0.34);
}

.landing-browser-bar {
  height: 2.2rem;
  border-bottom: 1px solid rgba(31, 27, 22, 0.08);
  background: rgba(248, 241, 226, 0.7);
}

.landing-sidebar-card,
.landing-board-card {
  background: rgba(250, 243, 223, 0.7);
  border: 1px solid rgba(31, 27, 22, 0.06);
  border-radius: 14px;
}

.landing-quote {
  font-family: var(--font-display);
  font-style: italic;
  color: var(--color-ink-light);
}

/* ── Persona margin notes — inline marks in the manuscript ── */
.twyne-persona-note {
  --note-color: var(--color-vermilion);
  cursor: pointer;
  background: color-mix(in srgb, var(--note-color) 11%, transparent);
  border-bottom: 2px dotted var(--note-color);
  transition: background 0.15s ease;
}
.twyne-persona-note:hover {
  background: color-mix(in srgb, var(--note-color) 22%, transparent);
}
.twyne-persona-note.is-flashing {
  animation: persona-note-flash 1.4s ease-out;
}
@keyframes persona-note-flash {
  0%,
  35% {
    background: color-mix(in srgb, var(--note-color) 38%, transparent);
  }
  100% {
    background: color-mix(in srgb, var(--note-color) 11%, transparent);
  }
}

.persona-note-card {
  position: fixed;
  z-index: var(--z-dropdown);
  width: min(20.5rem, calc(100vw - 1rem));
  padding: 0.85rem 1rem 1rem;
  background: var(--color-paper-soft);
  border: 1px solid color-mix(in srgb, var(--note-color) 45%, var(--color-paper-3));
  border-radius: 2px;
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.7) inset,
    0 18px 36px -20px rgba(31, 27, 22, 0.5);
  animation: persona-note-pop 0.18s cubic-bezier(0.22, 1, 0.36, 1);
}
@keyframes persona-note-pop {
  from {
    opacity: 0;
    transform: translateY(4px);
  }
  to {
    opacity: 1;
    transform: none;
  }
}
@media (prefers-reduced-motion: reduce) {
  .twyne-persona-note.is-flashing {
    animation: none;
    background: color-mix(in srgb, var(--note-color) 30%, transparent);
  }
  .persona-note-card {
    animation: none;
  }
}

/* ── Suggestions — an editor's proposed rewrite, as a red-pencil mark ── */
.twyne-suggestion {
  --suggestion-color: var(--color-vermilion);
  cursor: pointer;
  text-decoration: line-through;
  text-decoration-color: var(--suggestion-color);
  text-decoration-thickness: 2px;
  background: color-mix(in srgb, var(--suggestion-color) 9%, transparent);
  transition: background 0.15s ease;
}
.twyne-suggestion:hover {
  background: color-mix(in srgb, var(--suggestion-color) 20%, transparent);
}
.twyne-suggestion.is-flashing {
  animation: persona-note-flash 1.4s ease-out;
}

.suggestion-card {
  position: fixed;
  z-index: var(--z-dropdown);
  width: min(21rem, calc(100vw - 1rem));
  padding: 0.85rem 1rem 1rem;
  background: var(--color-paper-soft);
  border: 1px solid
    color-mix(in srgb, var(--suggestion-color) 45%, var(--color-paper-3));
  border-radius: 2px;
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.7) inset,
    0 18px 36px -20px rgba(31, 27, 22, 0.5);
  animation: persona-note-pop 0.18s cubic-bezier(0.22, 1, 0.36, 1);
}

/* The approval stamp — a vermilion rubber stamp thunking onto the page. */
.approval-stamp-overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  pointer-events: none;
  z-index: var(--z-modal, 1000);
}
.approval-stamp-overlay img {
  animation: stamp-thunk 1.2s cubic-bezier(0.18, 1.4, 0.4, 1) forwards;
  transform-origin: center;
  filter: drop-shadow(0 8px 18px rgba(139, 47, 36, 0.35));
}
@keyframes stamp-thunk {
  0% {
    opacity: 0;
    transform: scale(1.8) rotate(-14deg);
  }
  18% {
    opacity: 1;
    transform: scale(0.92) rotate(-7deg);
  }
  32% {
    transform: scale(1.04) rotate(-9deg);
  }
  46% {
    transform: scale(1) rotate(-8deg);
  }
  80% {
    opacity: 1;
    transform: scale(1) rotate(-8deg);
  }
  100% {
    opacity: 0;
    transform: scale(1.02) rotate(-8deg);
  }
}
@media (prefers-reduced-motion: reduce) {
  .twyne-suggestion.is-flashing {
    animation: none;
    background: color-mix(in srgb, var(--suggestion-color) 28%, transparent);
  }
  .suggestion-card {
    animation: none;
  }
  .approval-stamp-overlay img {
    animation: stamp-fade 1s ease-out forwards;
  }
  @keyframes stamp-fade {
    0% {
      opacity: 0;
    }
    20%,
    80% {
      opacity: 1;
      transform: rotate(-8deg);
    }
    100% {
      opacity: 0;
    }
  }
}

/* Landing masthead logotype, echoes the in-app masthead */
.landing-masthead {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 2rem;
  line-height: 1;
  letter-spacing: 0.06em;
  color: var(--color-ink);
}

.landing-masthead-grand {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(3.25rem, 10vw, 5.75rem);
  line-height: 1;
  letter-spacing: 0.05em;
  color: var(--color-ink);
}

/* Landing masthead nav */
.landing-nav-link {
  font-family: var(--font-typewriter);
  font-size: 0.78rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--color-ink-light);
  transition: color 0.15s ease;
}
.landing-nav-link:hover {
  color: var(--color-vermilion);
}
.landing-nav-link:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: 3px;
}

/* Annotation slips pinned over the workspace preview */
.landing-annotation {
  position: absolute;
  z-index: 2;
  pointer-events: none;
  max-width: 15.5rem;
  padding: 0.6rem 0.8rem;
  background: var(--color-paper-soft);
  border: 1px solid rgba(31, 27, 22, 0.2);
  border-radius: 2px;
  box-shadow: 0 14px 28px -18px rgba(31, 27, 22, 0.5);
}
.landing-annotation .tag {
  font-family: var(--font-typewriter);
  font-size: 0.72rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}
.landing-annotation .note {
  margin-top: 0.2rem;
  font-family: var(--font-serif);
  font-size: 0.875rem;
  line-height: 1.45;
  color: var(--color-ink-light);
}

/* Step numerals in the how-it-works ledger */
.landing-step-num {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.5rem;
  line-height: 1;
  color: var(--color-vermilion);
}

/* Hero entrance: starts visible-safe via `both` keyframe fill */
@keyframes landing-rise {
  from {
    opacity: 0;
    transform: translateY(16px);
  }
  to {
    opacity: 1;
    transform: none;
  }
}
.landing-rise,
.landing-rise-2,
.landing-rise-3 {
  animation: landing-rise 0.7s cubic-bezier(0.22, 1, 0.36, 1) both;
}
.landing-rise-2 {
  animation-delay: 0.12s;
}
.landing-rise-3 {
  animation-delay: 0.24s;
}
@media (prefers-reduced-motion: reduce) {
  .landing-rise,
  .landing-rise-2,
  .landing-rise-3 {
    animation: none;
  }
}

/* ─────────────────────────────────────────────────────────────
 * Paper primitives — shared across landing variants
 *   .paper-sheet      : aged newsprint with grain + foxing
 *   .paper-foxed      : adds little browned spots
 *   .paper-deckle     : torn/deckle bottom edge
 *   .paper-rule       : thin double rule, ink
 *   .ink-bleed        : letterpress-style soft ink halo
 *   .stamp-tilt       : rubber-stamp rotation utility
 * ───────────────────────────────────────────────────────────── */
.paper-sheet {
  position: relative;
  background-color: #f5ecd6;
  background-image:
    radial-gradient(
      circle at 18% 22%,
      rgba(122, 84, 38, 0.06) 0,
      transparent 38%
    ),
    radial-gradient(
      circle at 82% 78%,
      rgba(122, 84, 38, 0.05) 0,
      transparent 42%
    ),
    radial-gradient(
      circle at 50% 50%,
      rgba(255, 248, 220, 0.6) 0,
      transparent 60%
    ),
    repeating-linear-gradient(
      135deg,
      rgba(31, 27, 22, 0.018) 0 2px,
      transparent 2px 6px
    ),
    radial-gradient(
      circle at 30% 40%,
      rgba(31, 27, 22, 0.04) 0 1px,
      transparent 1.4px
    ),
    radial-gradient(
      circle at 70% 60%,
      rgba(31, 27, 22, 0.035) 0 1px,
      transparent 1.4px
    ),
    radial-gradient(
      circle at 15% 85%,
      rgba(31, 27, 22, 0.03) 0 1px,
      transparent 1.4px
    );
  background-size:
    auto,
    auto,
    auto,
    auto,
    5px 5px,
    7px 7px,
    9px 9px;
  box-shadow:
    inset 0 0 60px rgba(122, 84, 38, 0.08),
    inset 0 0 0 1px rgba(31, 27, 22, 0.04);
}
.paper-foxed::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  background-image:
    radial-gradient(
      circle at 12% 18%,
      rgba(140, 90, 36, 0.18) 0 1.2px,
      transparent 2.5px
    ),
    radial-gradient(
      circle at 88% 32%,
      rgba(140, 90, 36, 0.16) 0 0.9px,
      transparent 2px
    ),
    radial-gradient(
      circle at 24% 78%,
      rgba(140, 90, 36, 0.14) 0 1.4px,
      transparent 2.8px
    ),
    radial-gradient(
      circle at 76% 88%,
      rgba(140, 90, 36, 0.18) 0 1px,
      transparent 2.2px
    ),
    radial-gradient(
      circle at 50% 50%,
      rgba(140, 90, 36, 0.12) 0 0.8px,
      transparent 2px
    );
  opacity: 0.7;
  mix-blend-mode: multiply;
}
.paper-deckle {
  --deckle-color: #f5ecd6;
  position: relative;
}
.paper-deckle::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: -10px;
  height: 14px;
  background:
    radial-gradient(circle at 5% 0, var(--deckle-color) 6px, transparent 7px) 0
      0/14px 14px repeat-x,
    radial-gradient(circle at 50% 6px, var(--deckle-color) 8px, transparent 9px)
      7px 0/22px 14px repeat-x;
  filter: drop-shadow(0 2px 1px rgba(31, 27, 22, 0.08));
}
.paper-rule {
  border: 0;
  height: 5px;
  background: linear-gradient(
    to bottom,
    var(--color-ink) 0 1px,
    transparent 1px 3px,
    var(--color-ink) 3px 4px,
    transparent 4px
  );
  opacity: 0.65;
}
.paper-rule.thin {
  height: 1px;
  background: var(--color-ink);
  opacity: 0.35;
}
.ink-bleed {
  text-shadow:
    0 0 0.4px currentColor,
    0.3px 0.3px 0 rgba(31, 27, 22, 0.18),
    -0.2px -0.2px 0 rgba(31, 27, 22, 0.08);
}
.stamp-tilt {
  transform: rotate(-6deg);
}
.stamp-tilt-r {
  transform: rotate(4deg);
}

/* Halftone — old printed-image dot pattern */
.halftone {
  background-image: radial-gradient(
    circle,
    rgba(31, 27, 22, 0.55) 0 1px,
    transparent 1.4px
  );
  background-size: 4px 4px;
}

/* Variant switcher bar (shown above the landing) */
.variant-bar {
  position: fixed;
  top: 12px;
  right: 12px;
  z-index: 100;
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 6px;
  border-radius: 999px;
  background: rgba(245, 236, 214, 0.92);
  border: 1px solid rgba(31, 27, 22, 0.12);
  box-shadow: 0 12px 30px -18px rgba(31, 27, 22, 0.4);
  font-family: var(--font-typewriter);
  font-size: 0.65rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}
.variant-bar a {
  padding: 6px 12px;
  border-radius: 999px;
  color: var(--color-ink-muted);
  text-decoration: none;
}
.variant-bar a.active {
  background: var(--color-ink);
  color: var(--color-paper);
}

/* ─── Variant A — Broadsheet ─────────────────────────────── */
.broadsheet {
  background-color: #f5ecd6;
  min-height: 100vh;
}
.broadsheet-page {
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem 2.5rem 4rem;
  position: relative;
}
.broadsheet-masthead {
  text-align: center;
  border-top: 6px double var(--color-ink);
  border-bottom: 6px double var(--color-ink);
  padding: 1.5rem 0 1.25rem;
  margin-bottom: 1rem;
}
.broadsheet-nameplate {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(4rem, 12vw, 9rem);
  line-height: 0.85;
  letter-spacing: 0.05em;
  color: var(--color-ink);
  margin: 0.4rem 0 0.5rem;
}
.broadsheet-dateline {
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  border-bottom: 1px solid var(--color-ink);
  padding: 0.5rem 0.5rem;
  margin-bottom: 1.25rem;
}
.broadsheet-headline {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(2.5rem, 5.5vw, 4.5rem);
