}
.broadsheet-byline {
  text-align: center;
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
  margin-top: 1.25rem;
}
.broadsheet-cols {
  column-count: 3;
  column-gap: 2.25rem;
  column-rule: 1px solid rgba(31, 27, 22, 0.18);
  font-family: var(--font-serif);
  font-size: 1rem;
  line-height: 1.7;
  text-align: justify;
