  padding: 1.25rem 0;
  margin-top: 1rem;
}
.broadsheet-bulletin h3 {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.4rem;
  margin: 0 0 0.3rem;
  letter-spacing: -0.01em;
}
.broadsheet-bulletin p {
  font-family: var(--font-serif);
  font-size: 0.95rem;
  line-height: 1.55;
  color: var(--color-ink-light);
