}
.broadsheet-cta.secondary {
  background: transparent;
  color: var(--color-ink);
  border: 1px solid var(--color-ink);
}

/* ─── Variant B — Letterpress Quarterly ───────────────────── */
.quarterly {
  min-height: 100vh;
  background: radial-gradient(
    ellipse at top,
    #f8efd9 0%,
    #efe3c4 60%,
    #e6d8b3 100%
  );
  padding: 3rem 1rem 5rem;
}
.quarterly-cover {
  max-width: 720px;
  margin: 0 auto;
  padding: 4.5rem 3rem 5rem;
  text-align: center;
  position: relative;
  border: 1px solid rgba(31, 27, 22, 0.18);
  background: rgba(248, 240, 218, 0.85);
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.7) inset,
    0 60px 100px -60px rgba(31, 27, 22, 0.5);
}
.quarterly-cover::before {
  content: "";
