  background: var(--color-ink);
}
.quarterly-rule .ornament {
  font-family: var(--font-display);
  font-size: 1.4rem;
}
.quarterly-deck {
  font-family: var(--font-serif);
  font-size: 1.05rem;
  line-height: 1.75;
  color: var(--color-ink-light);
  max-width: 32rem;
  margin: 0 auto;
}
.quarterly-buttons {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 1rem;
  margin-top: 2.25rem;
}
.quarterly-button {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.95rem 1.6rem;
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  border: 1px solid var(--color-ink);
  background: var(--color-ink);
