  font-size: 1.6rem;
  color: var(--color-vermilion);
  font-style: italic;
}
.quarterly-entry h3 {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 1.2rem;
  margin: 0 0 0.35rem;
  color: var(--color-ink);
}
.quarterly-entry p {
  font-family: var(--font-serif);
  font-size: 0.92rem;
  line-height: 1.65;
  color: var(--color-ink-light);
  margin: 0;
}

/* ─── Variant C — Telegram Gazette ────────────────────────── */
.telegram {
  min-height: 100vh;
  background: #f4ecd8;
  padding: 2.5rem 1.5rem 4rem;
  font-family: var(--font-typewriter);
}
.telegram-sheet {
  max-width: 760px;
  margin: 0 auto;
  background: #fbf4dc;
  padding: 3rem 3rem 3.5rem;
  border: 1px solid rgba(31, 27, 22, 0.22);
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.6) inset,
    0 30px 60px -40px rgba(31, 27, 22, 0.45);
  position: relative;
}
.telegram-stamp {
  position: absolute;
  top: 1.5rem;
  right: 1.5rem;
  font-family: var(--font-typewriter);
  font-size: 0.6rem;
  letter-spacing: 0.3em;
  border: 2px solid var(--color-vermilion);
  color: var(--color-vermilion);
  padding: 0.35rem 0.6rem;
  text-transform: uppercase;
  transform: rotate(-7deg);
  background: rgba(193, 39, 45, 0.04);
}
.telegram-header {
  text-align: center;
  border-bottom: 2px solid var(--color-ink);
  padding-bottom: 1rem;
  margin-bottom: 1.5rem;
}
.telegram-header .from {
  font-size: 0.65rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
}
.telegram-header h1 {
  font-family: var(--font-typewriter);
  font-size: clamp(1.6rem, 3.5vw, 2.4rem);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  margin: 0.4rem 0 0;
  color: var(--color-ink);
}
.telegram-meta {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0.5rem 1.5rem;
  font-size: 0.62rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
  margin-bottom: 2rem;
  padding-bottom: 1rem;
  border-bottom: 1px dashed rgba(31, 27, 22, 0.3);
}
.telegram-meta strong {
  display: block;
  color: var(--color-ink);
  font-weight: 700;
  font-size: 0.8rem;
  letter-spacing: 0.14em;
  margin-top: 0.15rem;
}
.telegram-body {
  font-family: var(--font-typewriter);
  font-size: 1.05rem;
  line-height: 1.85;
  color: var(--color-ink);
  letter-spacing: 0.005em;
}
.telegram-body p {
  margin: 0 0 1.25em;
}
.telegram-body p::before {
  content: "";
}
.telegram-stop {
  display: inline-block;
  font-weight: 700;
  letter-spacing: 0.24em;
  color: var(--color-vermilion);
  margin: 0 0.35em;
}
.telegram-list {
  list-style: none;
  margin: 1.5rem 0;
  padding: 0;
  display: grid;
  gap: 0.6rem;
}
.telegram-list li {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: 0.85rem;
  font-size: 0.95rem;
  letter-spacing: 0.01em;
}
.telegram-list .num {
  color: var(--color-vermilion);
  font-weight: 700;
}
.telegram-actions {
  margin-top: 2.25rem;
  padding-top: 1.25rem;
  border-top: 2px solid var(--color-ink);
  display: flex;
  flex-wrap: wrap;
  gap: 0.85rem;
  align-items: center;
  justify-content: space-between;
}
.telegram-button {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.85rem 1.4rem;
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  background: var(--color-ink);
  color: var(--color-paper);
  border: 0;
  cursor: pointer;
}
.telegram-button.ghost {
  background: transparent;
  color: var(--color-ink);
  border: 1px dashed var(--color-ink);
}
.telegram-signoff {
  text-align: right;
  font-size: 0.68rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
  margin-top: 1.5rem;
}

/* ── Reduced motion ──────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .press,
  .animate-spin,
  .feedback-enter {
    animation: none !important;
  }
  /* The bar keeps its final inline width; only the fill sweep is dropped */
  .rubric-bar {
    animation: none !important;
  }
  .sidebar-transition,
  .landing-button,
  .landing-feature-card,
  .portrait {
    transition: none !important;
  }
  .landing-button:hover,
  .landing-feature-card:hover,
  .portrait:hover {
    transform: none !important;
  }
}

