          />
          <button
            onClick$={addComment}
            disabled={!store.newCommentText.trim()}
            class="btn-press mt-2 w-full"
          >
            Pencil it in
          </button>
        </div>

        <div class="flex-1 overflow-y-auto">
          {store.comments.length === 0 && (
            <div class="text-center py-10 px-6">
              <p
                class="text-3xl"
