                          >
                            {reply.author}
                            {reply.authorKind === "persona" && (
                              <span
                                class="ml-1.5 text-[0.55rem] tracking-[0.15em] uppercase text-[var(--color-ink-muted)]"
                                style="font-family: var(--font-typewriter);"
                              >
                                editor
