import {
  component$,
  useStore,
  useStylesScoped$,
  useVisibleTask$,
  $,
} from "@builder.io/qwik";
import { Link, type DocumentHead } from "@builder.io/qwik-city";
import { useConvexClient } from "../../utils/convex-context";
import { api } from "../../../convex/_generated/api";
import type { DetectedCitation, Folio, ProjectBrief } from "../../types";
import { detectCitations } from "../../utils/citations";
import { type Source } from "../../../convex/research";
import {
  type BibEntry,
  type CitationStyle,
  loadBibliography,
  upsertBibEntry,
  deleteBibEntry,
  formatCitation,
} from "../../utils/bibliography";
import { loadFoliosFromIdb, loadFolioContentFromIdb } from "../../utils/idb";

interface ApparatusStore {
  query: string;
  context: string;
  results: Source[];
  searchProvider: string | null;
  searching: boolean;
  error: string | null;
  bibliography: BibEntry[];
  citations: DetectedCitation[];
  style: CitationStyle;
  activeFolio: Folio | null;
  brief: ProjectBrief | null;
  hasSearched: boolean;
  embedUrl: string | null;
  embedTitle: string;
  embedMarkdown: string | null;
  embedProvider: string | null;
  embedLoading: boolean;
}

const STYLE_OPTIONS: ReadonlyArray<{ value: CitationStyle; label: string }> = [
  { value: "mla", label: "MLA" },
  { value: "apa", label: "APA" },
  { value: "chicago", label: "Chicago" },
];

export default component$(() => {
  const clientSig = useConvexClient();
  const store = useStore<ApparatusStore>({
    query: "",
    context: "",
    results: [],
    searchProvider: null,
    searching: false,
    error: null,
    bibliography: [],
    citations: [],
    style: "mla",
    activeFolio: null,
    brief: null,
    hasSearched: false,
    embedUrl: null,
    embedTitle: "",
    embedMarkdown: null,
    embedProvider: null,
    embedLoading: false,
  });

  // eslint-disable-next-line qwik/no-use-visible-task
  useVisibleTask$(async () => {
    store.bibliography = await loadBibliography();
    const folios = await loadFoliosFromIdb();
    store.activeFolio = folios[0] ?? null;
    if (store.activeFolio) {
      const html = await loadFolioContentFromIdb(store.activeFolio.id);
      const text = html.replace(/<[^>]+>/g, " ");
      store.citations = detectCitations(text);
    }
  });

  useStylesScoped$(`
    .toolbar {
      display: flex; gap: 0.5rem; align-items: center;
    }
    .style-toggle {
      display: inline-flex; border: 1px solid var(--color-paper-3);
      border-radius: 2px; overflow: hidden;
    }
    .style-toggle button {
      padding: 0.2rem 0.6rem;
      font-family: var(--font-typewriter);
      font-size: 0.7rem;
      letter-spacing: 0.1em;
      background: var(--color-paper-soft);
      color: var(--color-ink-light);
    }
    .style-toggle button[aria-pressed="true"] {
      background: var(--color-vermilion);
      color: var(--color-paper);
    }
    .card {
      border: 1px solid var(--color-paper-3);
      background: var(--color-paper);
      border-radius: 4px;
    }
    .row {
      padding: 0.85rem 1rem;
      border-bottom: 1px dashed var(--color-paper-3);
    }
    .row:last-child { border-bottom: none; }
    .empty {
      padding: 2rem 1rem;
      text-align: center;
      color: var(--color-ink-muted);
    }
    .badge {
      display: inline-block;
      padding: 0.1rem 0.45rem;
      border: 1px solid var(--color-paper-3);
      border-radius: 2px;
      font-family: var(--font-typewriter);
      font-size: 0.6rem;
      letter-spacing: 0.1em;
      text-transform: uppercase;
      color: var(--color-ink-muted);
    }
    .badge.cited {
      border-color: var(--color-accent-green);
      color: var(--color-accent-green);
    }
    .preview pre {
      white-space: pre-wrap;
      font-family: var(--font-serif);
      font-size: 0.85rem;
      line-height: 1.6;
      color: var(--color-ink);
      max-height: 60vh;
      overflow: auto;
    }
  `);

  const runSearch = $(async () => {
    if (!store.query.trim()) return;
    store.searching = true;
    store.error = null;
    store.hasSearched = true;
    const client = clientSig.value;
    try {
      if (client) {
        const res = await client.action(api.research.searchSources, {
          query: store.query,
          context: store.context || undefined,
        });
        store.results = res.results ?? [];
        store.searchProvider = res.provider;
      } else {
        throw new Error("Offline — connect once to enable research.");
      }
    } catch (err) {
      store.error = (err as Error).message;
      store.results = [];
    } finally {
      store.searching = false;
    }
  });

  const setStyle = $((s: CitationStyle) => {
    store.style = s;
  });

  const saveSource = $(async (src: Source) => {
    if (!src.url) return;
    const entry: BibEntry = {
      id: crypto.randomUUID(),
      folioId: store.activeFolio?.id ?? "",
      title: src.title || src.url,
      author: src.author,
      publisher: src.publisher,
      date: src.date,
      url: src.url,
      accessedAt: Date.now(),
      snippet: src.snippet,
      why: src.why,
      style: store.style,
    };
    const all = await upsertBibEntry(entry);
    store.bibliography = all;
  });

  const dropEntry = $(async (id: string) => {
    const all = await deleteBibEntry(id);
    store.bibliography = all;
  });

  const openEmbed = $(async (entry: BibEntry) => {
    store.embedUrl = entry.url;
    store.embedTitle = entry.title;
    store.embedMarkdown = null;
    store.embedProvider = null;
    store.embedLoading = true;
    const client = clientSig.value;
    try {
      if (client) {
        const res = await client.action(api.research.fetchSource, {
          url: entry.url,
        });
        store.embedMarkdown = res.markdown ?? "";
        store.embedProvider = res.provider;
      }
    } catch {
      store.embedMarkdown = "";
    } finally {
      store.embedLoading = false;
    }
  });

  const closeEmbed = $(() => {
    store.embedUrl = null;
    store.embedMarkdown = null;
    store.embedProvider = null;
  });

  const copyAll = $(async () => {
    const text = store.bibliography
      .map((b) => formatCitation(b, store.style))
      .join("\n\n");
    try {
      await navigator.clipboard?.writeText(text);
    } catch {
      /* ignore */
    }
  });

  const citedUrls = new Set(
    store.citations
      .map((c) => c.lookupUrl)
      .filter((u): u is string => !!u)
      .map((u) => u.replace(/\/+$/, "")),
  );

  return (
    <div
      class="min-h-screen bg-[var(--color-paper-soft)] text-[var(--color-ink)]"
      style={{ fontFamily: "var(--font-serif)" }}
    >
      <div class="max-w-5xl mx-auto px-6 py-8">
        <div class="flex items-center justify-between mb-6">
          <div>
            <p
              class="dept-label mb-1"
              style={{ fontFamily: "var(--font-typewriter)" }}
            >
              Twyne
            </p>
            <h1
              style={{
                fontFamily: "var(--font-display)",
                fontWeight: 700,
                fontSize: "1.75rem",
              }}
            >
              The Apparatus
            </h1>
            <p class="text-sm text-[var(--color-ink-light)] mt-1">
              Discover sources while you write. Save what is useful. Cite
              without breaking flow.
            </p>
          </div>
          <Link
            href="/"
            class="btn-paper text-sm"
            style={{ fontFamily: "var(--font-display)" }}
          >
            ← Back to desk
          </Link>
        </div>

        <div class="grid lg:grid-cols-[1fr_1.4fr] gap-6">
          {/* Left: search + discovered */}
          <section>
            <h2
              class="text-base font-semibold mb-2"
              style={{ fontFamily: "var(--font-display)" }}
            >
              Research
            </h2>
            <div class="card p-3 mb-3">
              <input
                type="text"
                value={store.query}
                onInput$={(e) => {
                  store.query = (e.target as HTMLInputElement).value;
                }}
                onKeyDown$={(e) => {
                  if (e.key === "Enter") void runSearch();
                }}
                placeholder="What are you trying to source?"
                class="w-full px-2 py-1.5 text-sm bg-[var(--color-paper-soft)] border border-[var(--color-paper-3)] focus:outline-none focus:border-[var(--color-vermilion)] text-[var(--color-ink)] placeholder:text-[var(--color-ink-muted)] placeholder:italic"
                style="font-family: var(--font-serif); border-radius: 2px;"
              />
              <input
                type="text"
                value={store.context}
                onInput$={(e) => {
                  store.context = (e.target as HTMLInputElement).value;
                }}
                placeholder="Context (optional — e.g. the brief's audience)"
                class="w-full mt-2 px-2 py-1.5 text-[0.7rem] bg-[var(--color-paper-soft)] border border-[var(--color-paper-3)] focus:outline-none focus:border-[var(--color-vermilion)] text-[var(--color-ink-light)] placeholder:text-[var(--color-ink-muted)]"
                style="font-family: var(--font-typewriter); border-radius: 2px;"
              />
              <button
                onClick$={runSearch}
                disabled={store.searching || !store.query.trim()}
                class="btn-press w-full mt-2 text-sm disabled:opacity-50"
              >
                {store.searching ? "Searching…" : "🔎 Find sources"}
              </button>
              {store.error && (
                <p
                  class="text-[0.7rem] text-[var(--color-vermilion)] mt-2"
                  style="font-family: var(--font-typewriter);"
                >
                  {store.error}
                </p>
              )}
              {store.searchProvider && (
                <p
                  class="text-[0.6rem] text-[var(--color-ink-muted)] mt-1"
                  style={{
                    fontFamily: "var(--font-typewriter)",
                    letterSpacing: "0.1em",
                  }}
                >
                  via {store.searchProvider}
                </p>
              )}
            </div>

            <div class="card">
              {store.results.length === 0 &&
                store.hasSearched &&
                !store.searching && (
                  <div class="empty">
                    <p class="text-xs italic">No results yet.</p>
                  </div>
                )}
              {store.results.length === 0 && !store.hasSearched && (
                <div class="empty">
                  <p
                    class="text-3xl"
                    style={{
                      fontFamily: "var(--font-display)",
                      color: "var(--color-periwinkle)",
                    }}
                  >
                    ❧
                  </p>
                  <p class="text-sm mt-2 italic">
                    Set <code>TINYFISH_API_KEY</code> for live results; the
                    panel falls back to a deterministic stub.
                  </p>
                </div>
              )}
              {store.results.map((r) => {
                const isCited =
                  r.url && citedUrls.has(r.url.replace(/\/+$/, ""));
                const isSaved = store.bibliography.some(
                  (b) =>
                    b.url === r.url || b.url === r.url?.replace(/\/+$/, ""),
                );
                return (
                  <div key={r.url} class="row">
                    <div class="flex items-start justify-between gap-2">
                      <div class="min-w-0 flex-1">
                        <p
                          class="text-sm text-[var(--color-ink)]"
                          style={{
                            fontFamily: "var(--font-display)",
                            fontWeight: 600,
                          }}
                        >
                          {r.title}
                        </p>
                        <p
                          class="text-[0.65rem] text-[var(--color-ink-muted)] mt-0.5 break-all"
                          style={{ fontFamily: "var(--font-mono)" }}
                        >
                          {r.url}
                        </p>
                        {r.snippet && (
                          <p
                            class="text-xs text-[var(--color-ink-light)] mt-1.5 leading-5"
                            style={{ fontFamily: "var(--font-serif)" }}
                          >
                            {r.snippet}
                          </p>
                        )}
                        <p
                          class="text-[0.6rem] text-[var(--color-ink-muted)] mt-1"
                          style={{ fontFamily: "var(--font-typewriter)" }}
                        >
                          {[r.author, r.publisher, r.date]
                            .filter(Boolean)
                            .join(" · ")}
                        </p>
                      </div>
                    </div>
                    <div class="mt-2 flex items-center gap-2 flex-wrap">
                      <button
                        onClick$={() => saveSource(r)}
                        disabled={isSaved}
                        class="text-[0.6rem] tracking-[0.15em] uppercase px-1.5 py-0.5 border"
                        style={{
                          fontFamily: "var(--font-typewriter)",
                          borderColor: isSaved
                            ? "var(--color-accent-green)"
                            : "var(--color-vermilion)",
                          color: isSaved
                            ? "var(--color-accent-green)"
                            : "var(--color-vermilion)",
                          borderRadius: "1px",
                          opacity: isSaved ? 0.7 : 1,
                        }}
                      >
                        {isSaved ? "✓ saved" : "+ save"}
                      </button>
                      {isCited && <span class="badge cited">cited</span>}
                    </div>
                  </div>
                );
              })}
            </div>
          </section>

          {/* Right: bibliography + cross-reference */}
          <section>
            <div class="flex items-center justify-between mb-2">
              <h2
                class="text-base font-semibold"
                style={{ fontFamily: "var(--font-display)" }}
              >
                Bibliography
              </h2>
              <div class="toolbar">
                <div
                  class="style-toggle"
                  role="group"
                  aria-label="Citation style"
                >
                  {STYLE_OPTIONS.map((s) => (
                    <button
                      key={s.value}
                      onClick$={() => setStyle(s.value)}
                      aria-pressed={store.style === s.value}
                    >
                      {s.label}
                    </button>
                  ))}
                </div>
                <button
                  onClick$={copyAll}
                  class="text-[0.6rem] tracking-[0.15em] uppercase text-[var(--color-ink-muted)] hover:text-[var(--color-accent)]"
                  style="font-family: var(--font-typewriter);"
                >
                  Copy all
                </button>
              </div>
            </div>
            <div class="card mb-4">
              {store.bibliography.length === 0 ? (
                <div class="empty">
                  <p
                    class="text-3xl"
                    style={{
                      fontFamily: "var(--font-display)",
                      color: "var(--color-cobalt)",
                    }}
                  >
                    ✎
                  </p>
                  <p class="text-sm mt-2 italic">No saved sources yet.</p>
                </div>
              ) : (
                store.bibliography.map((entry) => {
                  const isCited = citedUrls.has(entry.url.replace(/\/+$/, ""));
                  return (
                    <div key={entry.id} class="row">
                      <div class="flex items-start justify-between gap-2">
                        <div class="min-w-0 flex-1">
                          <p
                            class="text-sm text-[var(--color-ink)]"
                            style={{
                              fontFamily: "var(--font-display)",
                              fontWeight: 600,
                            }}
                          >
                            {entry.title}
                          </p>
                          <p
                            class="text-[0.65rem] text-[var(--color-ink-muted)] mt-0.5 break-all"
                            style={{ fontFamily: "var(--font-mono)" }}
                          >
                            {entry.url}
                          </p>
                          <p
                            class="text-xs text-[var(--color-ink-light)] mt-1.5 leading-5"
                            style={{ fontFamily: "var(--font-serif)" }}
                          >
                            {formatCitation(entry, store.style)}
                          </p>
                          {isCited && (
                            <span class="badge cited mt-1.5 inline-block">
                              cited in draft
                            </span>
                          )}
                        </div>
                      </div>
                      <div class="mt-2 flex items-center gap-2 flex-wrap">
                        <button
                          onClick$={() => openEmbed(entry)}
                          class="text-[0.6rem] tracking-[0.15em] uppercase text-[var(--color-ink-muted)] hover:text-[var(--color-accent)]"
                          style="font-family: var(--font-typewriter);"
                        >
                          ⌖ open
                        </button>
                        <button
                          onClick$={() => dropEntry(entry.id)}
                          class="text-[0.6rem] tracking-[0.15em] uppercase text-[var(--color-ink-muted)] hover:text-[var(--color-vermilion)]"
                          style="font-family: var(--font-typewriter);"
                        >
                          ✕ drop
                        </button>
                      </div>
                    </div>
                  );
                })
              )}
            </div>

            <h2
              class="text-base font-semibold mb-2"
              style={{ fontFamily: "var(--font-display)" }}
            >
              Detected in the manuscript
            </h2>
            <div class="card">
              {store.citations.length === 0 ? (
                <div class="empty">
                  <p class="text-xs italic">
                    {store.activeFolio
                      ? "No DOI / URL / ISBN / author-year citations detected yet — keep writing."
                      : "No active folio to scan."}
                  </p>
                </div>
              ) : (
                store.citations.map((c) => (
                  <div key={c.id} class="row">
                    <p
                      class="text-xs text-[var(--color-ink)] break-all"
                      style={{ fontFamily: "var(--font-mono)" }}
                    >
                      {c.text}
                    </p>
                    <p
                      class="text-[0.6rem] text-[var(--color-ink-muted)] mt-0.5"
                      style={{ fontFamily: "var(--font-typewriter)" }}
                    >
                      {c.type}
                      {c.lookupUrl ? (
                        <>
                          {" · "}
                          <a
                            href={c.lookupUrl}
                            target="_blank"
                            rel="noopener noreferrer"
                            class="hover:text-[var(--color-accent)]"
                          >
                            look up ↗
                          </a>
                        </>
                      ) : null}
                    </p>
                  </div>
                ))
              )}
            </div>
          </section>
        </div>

        {/* Embed overlay */}
        {store.embedUrl && (
          <div
            class="fixed inset-0 z-50 flex items-center justify-center p-6"
            style="background: rgba(20, 16, 10, 0.55);"
            role="dialog"
            aria-label={`Preview: ${store.embedTitle}`}
            onClick$={closeEmbed}
          >
            <div
              class="bg-[var(--color-paper)] border border-[var(--color-paper-3)] w-full max-w-3xl max-h-[85vh] flex flex-col preview"
              style="border-radius: 2px;"
              onClick$={(e) => e.stopPropagation()}
            >
              <div class="px-5 py-3 border-b border-[var(--color-paper-3)] flex items-center justify-between gap-3">
                <div class="min-w-0">
                  <p
                    class="text-sm text-[var(--color-ink)] truncate"
                    style={{
                      fontFamily: "var(--font-display)",
                      fontWeight: 600,
                    }}
                  >
                    {store.embedTitle}
                  </p>
                  <p
                    class="text-[0.6rem] text-[var(--color-ink-muted)] truncate"
                    style={{ fontFamily: "var(--font-mono)" }}
                  >
                    {store.embedUrl}
                  </p>
                </div>
                <div class="flex items-center gap-2">
                  <a
                    href={store.embedUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    class="text-[0.65rem] tracking-[0.15em] uppercase text-[var(--color-ink-muted)] hover:text-[var(--color-accent)]"
                    style="font-family: var(--font-typewriter);"
                  >
                    Open ↗
                  </a>
                  <button
                    onClick$={closeEmbed}
                    class="text-[0.65rem] tracking-[0.15em] uppercase text-[var(--color-ink-muted)] hover:text-[var(--color-vermilion)]"
                    style="font-family: var(--font-typewriter);"
                  >
                    ✕
                  </button>
                </div>
              </div>
              <div class="flex-1 overflow-auto p-5">
                {store.embedLoading ? (
                  <p
                    class="text-xs text-[var(--color-ink-muted)]"
                    style="font-family: var(--font-typewriter);"
                  >
                    Fetching clean markdown…
                  </p>
                ) : store.embedMarkdown ? (
                  <pre>{store.embedMarkdown}</pre>
                ) : (
                  <iframe
                    src={store.embedUrl}
                    title={store.embedTitle}
                    class="w-full h-[60vh] border border-[var(--color-paper-3)]"
                    sandbox="allow-scripts allow-same-origin allow-popups"
                  />
                )}
              </div>
              {store.embedProvider && (
                <p
                  class="px-5 py-2 border-t border-[var(--color-paper-3)] text-[0.6rem] text-[var(--color-ink-muted)]"
                  style="font-family: var(--font-typewriter); letter-spacing: 0.1em;"
                >
                  via {store.embedProvider}
                </p>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
});

export const head: DocumentHead = {
  title: "The Apparatus · Twyne",
  meta: [
    {
      name: "description",
      content:
        "Research + bibliography for the Twyne writer. Discover sources, save what is useful, cite without breaking flow.",
    },
  ],
};

