               onClick$={() => runCommand("blockquote")}
               class="tool-btn"
             >
               ❝ pull
             </button>
             <button
               title="Code block"
               aria-label="Code block"
               aria-pressed={!!store.active.code}
               onClick$={() => runCommand("code")}
               class="tool-btn"
             >
               {"</>"}
             </button>
           </div>

           <Sep />

           <div class="flex items-center">
             <button
