                       class={`flex-1 text-[0.7rem] py-1 border ${store.layout.width === w ? "border-[var(--color-vermilion)] text-[var(--color-vermilion)]" : "border-[var(--color-paper-3)] text-[var(--color-ink-light)]"}`}
