display.text:
import type { Folio } from "../types";
import type { RubricResult } from "../types";

const DB_NAME = "twyne-lix-store";
const STORE_NAME = "lix-blobs";
const BLOB_KEY = "twyne-main";
const DRAFT_KEY = "twyne-draft-html";
const FOLIOS_KEY = "twyne-folios";
const ACTIVE_FOLIO_KEY = "twyne-active-folio";
const RUBRIC_KEY = "twyne-rubric-result";

function openDb(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, 1);
    request.onupgradeneeded = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME);
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

export async function loadLixBlobFromIdb(): Promise<Blob | null> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readonly");
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(BLOB_KEY);
      request.onsuccess = () => {
        const result = request.result;
        resolve(result instanceof Blob ? result : null);
      };
      request.onerror = () => reject(request.error);
    });
  } catch {
    return null;
  }
}

export async function saveLixBlobToIdb(blob: Blob): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(blob, BLOB_KEY);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // IDB unavailable
  }
}

export async function removeLixBlobFromIdb(): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.delete(BLOB_KEY);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // IDB unavailable
  }
}

/** Simple keyval store for draft HTML — avoids LIX JSON plugin churn. */
export async function loadDraftHtmlFromIdb(): Promise<string | null> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readonly");
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(DRAFT_KEY);
      request.onsuccess = () => {
        const result = request.result;
        const value = typeof result === "string" ? result : null;
        console.warn(
          "[twyne:idb] loadDraftHtmlFromIdb:",
          value === null ? "null" : `length ${value.length}`,
        );
        resolve(value);
      };
      request.onerror = () => reject(request.error);
    });
  } catch (e) {
    console.warn("[twyne:idb] loadDraftHtmlFromIdb FAILED:", e);
    return null;
  }
}

/** Nuke every row in the store — useful after schema changes. */
export async function clearIdbStore(): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.clear();
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

export async function saveDraftHtmlToIdb(html: string): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(html, DRAFT_KEY);
      request.onsuccess = () => {
        console.warn("[twyne:idb] saveDraftHtmlToIdb OK, length:", html.length);
        resolve();
      };
      request.onerror = () => reject(request.error);
    });
  } catch (e) {
    console.warn("[twyne:idb] saveDraftHtmlToIdb FAILED:", e);
  }
}

/* ── Multi-folio storage ─────────────────────────────────────── */

export async function loadFoliosFromIdb(): Promise<Folio[]> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readonly");
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(FOLIOS_KEY);
      request.onsuccess = () => {
        const result = request.result;
        resolve(Array.isArray(result) ? result : []);
      };
      request.onerror = () => reject(request.error);
    });
  } catch {
    return [];
  }
}

export async function saveFoliosToIdb(folios: Folio[]): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(folios, FOLIOS_KEY);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

export async function loadFolioContentFromIdb(id: string): Promise<string> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readonly");
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(`twyne-folio-${id}`);
      request.onsuccess = () => {
        const result = request.result;
        resolve(typeof result === "string" ? result : "");
      };
      request.onerror = () => reject(request.error);
    });
  } catch {
    return "";
  }
}

export async function saveFolioContentToIdb(
  id: string,
  html: string,
): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(html, `twyne-folio-${id}`);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

export async function removeFolioFromIdb(id: string): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.delete(`twyne-folio-${id}`);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

export async function loadActiveFolioIdFromIdb(): Promise<string | null> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readonly");
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(ACTIVE_FOLIO_KEY);
      request.onsuccess = () => {
        const result = request.result;
        resolve(typeof result === "string" ? result : null);
      };
      request.onerror = () => reject(request.error);
    });
  } catch {
    return null;
  }
}

export async function saveActiveFolioIdToIdb(id: string): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(id, ACTIVE_FOLIO_KEY);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

/* ── Custom personas storage ─────────────────────────────────── */

const PERSONAS_KEY = "twyne-custom-personas";

export async function loadPersonasFromIdb(): Promise<
  import("../types").Persona[] | null
> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readonly");
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(PERSONAS_KEY);
      request.onsuccess = () => {
        const result = request.result;
        resolve(Array.isArray(result) ? result : null);
      };
      request.onerror = () => reject(request.error);
    });
  } catch {
    return null;
  }
}

export async function savePersonasToIdb(
  personas: import("../types").Persona[],
): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(personas, PERSONAS_KEY);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

/* ── Last rubric result (so /rubric page can show the full breakdown) ── */

export async function loadRubricResultFromIdb(): Promise<RubricResult | null> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readonly");
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(RUBRIC_KEY);
      request.onsuccess = () => {
        const result = request.result;
        resolve(
          result && typeof result === "object"
            ? (result as RubricResult)
            : null,
        );
      };
      request.onerror = () => reject(request.error);
    });
  } catch {
    return null;
  }
}

export async function saveRubricResultToIdb(
  result: RubricResult,
): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(result, RUBRIC_KEY);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

