      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

/* ── AI Settings (BYOK) — stored client-side only ─────────────── */

const AI_SETTINGS_KEY = "twyne-ai-settings";

export async function loadAiSettingsFromIdb(): Promise<
  import("../types").AiSettings | null
> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readonly");
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(AI_SETTINGS_KEY);
      request.onsuccess = () => {
        const result = request.result;
        if (
          result &&
          typeof result === "object" &&
          "advancedMode" in result
        ) {
          resolve(result as import("../types").AiSettings);
        } else {
          resolve(null);
        }
      };
      request.onerror = () => reject(request.error);
    });
  } catch {
    return null;
  }
}

export async function saveAiSettingsToIdb(
  settings: import("../types").AiSettings,
): Promise<void> {
  try {
    const db = await openDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(settings, AI_SETTINGS_KEY);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  } catch {
    // noop
  }
}

